#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;
const long long mod=(1ll<<31);

struct Query{
    int n,m,a,id;
    bool operator<(Query x)const{
        return a<x.a;
    }
}p[N];

int q,num[N],mu[N],pr[N],cnt;
long long c[N],d[N],ans[N];
bool np[N];

bool cmp(int x,int y){
    return d[x]<d[y];
}

void init(){
    np[0]=np[1]=1;
    mu[1]=1;
    for(int i=2;i<N;i++){
        if(!np[i]) pr[++cnt]=i,mu[i]=-1;
        for(int j=1;1ll*pr[j]*i<N;j++){
            np[pr[j]*i]=1;
            if(i%pr[j]==0) break;
            mu[pr[j]*i]=-mu[i];
        }
    }
    for(int i=1;i<N;i++){
        num[i]=i;
        for(int j=1;j*j<=i;j++)
            if(i%j==0){
                d[i]+=j;
                if(j*j<i) d[i]+=i/j;
            }
    }
    sort(num+1,num+N,cmp);
}

void add(int x,long long k){
    for(;x<N;x+=(x&(-x)))
        c[x]=(c[x]+k)%mod;
}

int ask(int x){
    long long res=0;
    for(;x;x-=(x&(-x)))
       res=(res+c[x])%mod;
    return res;
}

void Insert(int x){
    for(int i=x;i<N;i+=x)
        add(i,mu[i/x]*d[x]%mod);
}

int main(){
    init();
    scanf("%d",&q);
    for(int i=1;i<=q;i++){
        scanf("%d%d%d",&p[i].n,&p[i].m,&p[i].a);
        p[i].id=i;
    }
    sort(p+1,p+q+1);
    for(int i=1,j=1;i<=q;i++){
        while(j<N && d[num[j]]<=p[i].a){
            Insert(num[j]);
            j++;
        }
        int n=p[i].n,m=p[i].m;
        long long res=0;
        for(int l=1,r;l<=min(n,m);l=r+1){
            r=min(n/(n/l),m/(m/l));
            res=(res+1ll*(n/l)*(m/l)%mod*(ask(r)-ask(l-1)))%mod;
        }
        ans[p[i].id]=(res+mod)%mod;
    }
    for(int i=1;i<=q;i++)
        printf("%d\n",ans[i]);
    return 0;
}
